LLM-Generated Parallel Code
void matmul_parallel(float* A, float* B, float* C, int n) {
#pragma omp parallel for collapse(2) schedule(dynamic)
for (int i = 0; i < n; i++) {
for (int j = 0; j < n; j++) {
float sum = 0.0f;
for (int k = 0; k < n; k++) {
sum += A[i*n + k] * B[k*n + j];
}
C[i*n + j] = sum;
}
}
}
